+        match result {
+            WINDOWS_CSTR_LESS_THAN => Ordering::Less,
+            WINDOWS_CSTR_EQUAL => Ordering::Equal,
+            WINDOWS_CSTR_GREATER_THAN => Ordering::Greater,
+            _ => self.utf16.cmp(&other.utf16),
